public class OperatorsExample {
    public static void main(String[] args) {
        // Arithmetic
        int a = 10, b = 3;
        System.out.println("a + b = " + (a + b));
        System.out.println("a - b = " + (a - b));
        System.out.println("a * b = " + (a * b));
        System.out.println("a / b = " + (a / b));
        System.out.println("a % b = " + (a % b));

        // Relational
        System.out.println("a > b? " + (a > b));
        System.out.println("a == b? " + (a == b));

        // Logical
        boolean x = true, y = false;
        System.out.println("x && y = " + (x && y));
        System.out.println("x || y = " + (x || y));
        System.out.println("!x = " + !x);

        // Ternary
        int max = (a > b) ? a : b;
        System.out.println("Max: " + max);
    }
}

