phase3.solution:
public class OperatorsPractice {
    public static void main(String[] args) {
        int x = 15, y = 4;
        System.out.println("x + y = " + (x + y));
        System.out.println("x - y = " + (x - y));
        System.out.println("x * y = " + (x * y));
        System.out.println("x / y = " + (x / y));
        System.out.println("x % y = " + (x % y));
        System.out.println((x > y) ? "15 is bigger" : "4 is bigger");
    }
}
